        Product p1 = new Product();
        p1.name = "Apple iPhone";
        p1.price = 79999.0;
        p1.inStock = true;

        Product p2 = new Product();
        p2.name = "Sony Headphones";
        p2.price = 14999.0;
        p2.inStock = false;

        System.out.println(p1.describe());
        System.out.println(p2.describe());
    }
}

class Product {
    String name;
    double price;
    boolean inStock;
}

public class App {
    public static void main(String[] args) {
        Product[] products = new Product[4];

        products[0] = new Product();
        products[0].name = "Mouse";
        products[0].price = 599.0;

        products[1] = new Product();
        products[1].name = "Keyboard";
        products[1].price = 2499.0;

        products[2] = new Product();
        products[2].name = "Monitor";
        products[2].price = 18999.0;

        products[3] = new Product();
        products[3].name = "Webcam";
        products[3].price = 3499.0;

        Product expensive = findMostExpensive(products);
        System.out.println("Most expensive: " + expensive.name + " at ₹" + expensive.price);
    }

    public static Product findMostExpensive(Product[] products) {
        Product max = products[0];
        for (Product p : products) {
            if (p.price > max.price) {
                max = p;
            }
        }
        return max;
    }
}

class Account {
    int accountId;
    String holderName;
    double balance;

    void deposit(double amount) {
        balance += amount;
    }

    void withdraw(double amount) {
        if (amount > balance) {
            System.out.println("Insufficient funds");
        } else {
            balance -= amount;
        }
    }

    void display() {
        System.out.println("Account #" + accountId + " [" + holderName + "]: ₹" + balance);
    }
}

public class Bank {
    public static void main(String[] args) {
        Account a1 = new Account();
        a1.accountId = 101;
        a1.holderName = "Aisha";
        a1.balance = 5000;

        Account a2 = new Account();
        a2.accountId = 102;
        a2.holderName = "Raj";
        a2.balance = 3000;

        a1.deposit(2000);
        a1.withdraw(1500);

        a2.withdraw(5000);

        a1.display();
        a2.display();
    }
}
